public class LCA {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static TreeNode lca(TreeNode root, TreeNode p, TreeNode q){
        if(root==null||root==p||root==q)return root;
        TreeNode l=lca(root.left,p,q), r=lca(root.right,p,q);
        return l!=null&&r!=null?root:l!=null?l:r;}
    public static void main(String[] a){
        TreeNode r=new TreeNode(3);r.left=new TreeNode(5);r.right=new TreeNode(1);
        r.left.left=new TreeNode(6);r.left.right=new TreeNode(2);
        System.out.println(lca(r,r.left,r.right).val);   // 3
        System.out.println(lca(r,r.left,r.left.right).val); // 5
        System.out.println("Both non-null from subtrees → current node is LCA");
    }
}

public class Balanced {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static int height(TreeNode r){
        if(r==null)return 0;
        int l=height(r.left);if(l==-1)return -1;
        int ri=height(r.right);if(ri==-1)return -1;
        return Math.abs(l-ri)>1?-1:1+Math.max(l,ri);}
    static boolean isBalanced(TreeNode r){return height(r)!=-1;}
    public static void main(String[] a){
        TreeNode r=new TreeNode(3);r.left=new TreeNode(9);r.right=new TreeNode(20);
        r.right.left=new TreeNode(15);r.right.right=new TreeNode(7);
        System.out.println(isBalanced(r)); // true
        TreeNode r2=new TreeNode(1);r2.left=new TreeNode(2);r2.left.left=new TreeNode(3);r2.left.left.left=new TreeNode(4);
        System.out.println(isBalanced(r2)); // false
        System.out.println("Return -1 from height to signal imbalance early — O(n) not O(n²)");
    }
}

public class PathSum {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static boolean hasPathSum(TreeNode r, int target){
        if(r==null)return false;
        target-=r.val;
        if(r.left==null&&r.right==null)return target==0;
        return hasPathSum(r.left,target)||hasPathSum(r.right,target);}
    public static void main(String[] a){
        TreeNode r=new TreeNode(5);r.left=new TreeNode(4);r.right=new TreeNode(8);
        r.left.left=new TreeNode(11);r.left.left.left=new TreeNode(7);r.left.left.right=new TreeNode(2);
        System.out.println(hasPathSum(r,22)); // true (5+4+11+2)
        System.out.println(hasPathSum(r,27)); // false
        System.out.println("Subtract at each node; check at leaf. O(n)");
    }
}

public class MaxPathSum {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static int maxSum=Integer.MIN_VALUE;
    static int dfs(TreeNode r){
        if(r==null)return 0;
        int l=Math.max(dfs(r.left),0), ri=Math.max(dfs(r.right),0);
        maxSum=Math.max(maxSum,r.val+l+ri); // path through current node
        return r.val+Math.max(l,ri);        // best single branch upward
    }
    static int maxPathSum(TreeNode r){maxSum=Integer.MIN_VALUE;dfs(r);return maxSum;}
    public static void main(String[] a){
        TreeNode r=new TreeNode(-10);r.left=new TreeNode(9);r.right=new TreeNode(20);
        r.right.left=new TreeNode(15);r.right.right=new TreeNode(7);
        System.out.println(maxPathSum(r)); // 42 (15+20+7)
        System.out.println("max(0,child) ignores negative branches. Update global with l+node+r.");
    }
}

public class Cameras {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static int cams=0;
    // 0=uncovered, 1=has camera, 2=covered by child camera
    static int dfs(TreeNode r){
        if(r==null)return 2;
        int l=dfs(r.left), ri=dfs(r.right);
        if(l==0||ri==0){cams++;return 1;}        // child uncovered: place camera
        if(l==1||ri==1)return 2;                  // child has camera: covered
        return 0;                                   // both children covered: uncovered
    }
    static int minCams(TreeNode r){cams=0;if(dfs(r)==0)cams++;return cams;}
    public static void main(String[] a){
        TreeNode r=new TreeNode(0);r.left=new TreeNode(0);r.left.left=new TreeNode(0);r.left.right=new TreeNode(0);
        System.out.println(minCams(r)); // 1
        System.out.println("Greedy postorder: place camera at parent when child is uncovered. O(n)");
    }
}

public class Invert {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static TreeNode invert(TreeNode r){
        if(r==null)return null;
        TreeNode tmp=r.left;r.left=invert(r.right);r.right=invert(tmp);
        return r;}
    static String str(TreeNode r){if(r==null)return"#";return r.val+"("+str(r.left)+","+str(r.right)+")";}
    public static void main(String[] a){
        TreeNode r=new TreeNode(4);r.left=new TreeNode(2);r.right=new TreeNode(7);
        r.left.left=new TreeNode(1);r.left.right=new TreeNode(3);r.right.left=new TreeNode(6);r.right.right=new TreeNode(9);
        TreeNode inv=invert(r);
        System.out.println(inv.left.val); // 7
        System.out.println(inv.right.val); // 2
        System.out.println("Swap children at every node. tmp=left; left=invert(right); right=invert(tmp)");
    }
}

import java.util.*;
public class SerDeser {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static String serialize(TreeNode r){
        if(r==null)return"null";
        return r.val+","+serialize(r.left)+","+serialize(r.right);}
    static TreeNode deserialize(String s){
        return deH(new ArrayDeque<>(Arrays.asList(s.split(","))));}
    static TreeNode deH(Deque<String> q){
        String v=q.poll();if(v.equals("null"))return null;
        TreeNode n=new TreeNode(Integer.parseInt(v));n.left=deH(q);n.right=deH(q);return n;}
    public static void main(String[] a){
        TreeNode r=new TreeNode(1);r.left=new TreeNode(2);r.right=new TreeNode(3);
        r.right.left=new TreeNode(4);r.right.right=new TreeNode(5);
        String s=serialize(r);System.out.println(s.startsWith("1,2,null"));
        TreeNode back=deserialize(s);System.out.println(back.right.left.val);
        System.out.println("Preorder serialize with 'null' markers. Deserialize: use queue, consume front.");
    }
}

import java.util.*;
public class AllPaths {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static List<String> paths=new ArrayList<>();
    static void dfs(TreeNode r, String path){
        if(r==null)return;
        path+=r.val;
        if(r.left==null&&r.right==null){paths.add(path);return;}
        dfs(r.left,path+"->");dfs(r.right,path+"->");}
    static List<String> binaryTreePaths(TreeNode r){paths=new ArrayList<>();dfs(r,"");return paths;}
    public static void main(String[] a){
        TreeNode r=new TreeNode(1);r.left=new TreeNode(2);r.right=new TreeNode(3);r.left.right=new TreeNode(5);
        System.out.println(binaryTreePaths(r)); // [1->2->5, 1->3]
        System.out.println("DFS with path string; add on leaf. O(n) time O(n*h) space");
    }
}

public class LCABST {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static TreeNode lcaBST(TreeNode r, int p, int q){
        if(p<r.val&&q<r.val)return lcaBST(r.left,p,q);
        if(p>r.val&&q>r.val)return lcaBST(r.right,p,q);
        return r;}
    public static void main(String[] a){
        TreeNode r=new TreeNode(6);r.left=new TreeNode(2);r.right=new TreeNode(8);
        r.left.left=new TreeNode(0);r.left.right=new TreeNode(4);r.left.right.left=new TreeNode(3);
        System.out.println(lcaBST(r,2,8).val); // 6
        System.out.println(lcaBST(r,2,4).val); // 2
        System.out.println("BST LCA: both < root → go left; both > root → go right; else root is LCA");
    }
}

public class CountComplete {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static int leftH(TreeNode r){int h=0;while(r!=null){h++;r=r.left;}return h;}
    static int rightH(TreeNode r){int h=0;while(r!=null){h++;r=r.right;}return h;}
    static int count(TreeNode r){
        if(r==null)return 0;
        int l=leftH(r),ri=rightH(r);
        if(l==ri)return(1<<l)-1; // perfect subtree
        return 1+count(r.left)+count(r.right);}
    public static void main(String[] a){
        TreeNode r=new TreeNode(1);r.left=new TreeNode(2);r.right=new TreeNode(3);
        r.left.left=new TreeNode(4);r.left.right=new TreeNode(5);r.right.left=new TreeNode(6);
        System.out.println(count(r)); // 6
        System.out.println("O(log²n): compare left/right heights. If equal: full subtree = 2^h-1");
    }
}

public class T2Synth {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static TreeNode lca(TreeNode r,TreeNode p,TreeNode q){if(r==null||r==p||r==q)return r;TreeNode l=lca(r.left,p,q),ri=lca(r.right,p,q);return l!=null&&ri!=null?r:l!=null?l:ri;}
    static boolean bal(TreeNode r){return h(r)!=-1;}
    static int h(TreeNode r){if(r==null)return 0;int l=h(r.left);if(l<0)return-1;int ri=h(r.right);if(ri<0)return-1;return Math.abs(l-ri)>1?-1:1+Math.max(l,ri);}
    static boolean ps(TreeNode r,int t){if(r==null)return false;t-=r.val;if(r.left==null&&r.right==null)return t==0;return ps(r.left,t)||ps(r.right,t);}
    public static void main(String[] a){
        TreeNode r=new TreeNode(3);r.left=new TreeNode(5);r.right=new TreeNode(1);r.left.left=new TreeNode(6);r.left.right=new TreeNode(2);
        System.out.println("lca="+lca(r,r.left,r.right).val);
        System.out.println("bal="+bal(r));
        TreeNode ps_r=new TreeNode(5);ps_r.left=new TreeNode(4);ps_r.left.left=new TreeNode(11);ps_r.left.left.right=new TreeNode(2);
        System.out.println("pathSum22="+ps(ps_r,22));
        boolean ok=lca(r,r.left,r.right).val==3&&bal(r)&&ps(ps_r,22);
        System.out.println("All pass: "+ok);
    }
}

public class T2Final {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static TreeNode lca(TreeNode r,TreeNode p,TreeNode q){if(r==null||r==p||r==q)return r;TreeNode l=lca(r.left,p,q),ri=lca(r.right,p,q);return l!=null&&ri!=null?r:l!=null?l:ri;}
    static int maxPathSum(TreeNode r){int[]m={Integer.MIN_VALUE};mps(r,m);return m[0];}
    static int mps(TreeNode r,int[]m){if(r==null)return 0;int l=Math.max(mps(r.left,m),0),ri=Math.max(mps(r.right,m),0);m[0]=Math.max(m[0],r.val+l+ri);return r.val+Math.max(l,ri);}
    static boolean pathSum(TreeNode r,int t){if(r==null)return false;t-=r.val;if(r.left==null&&r.right==null)return t==0;return pathSum(r.left,t)||pathSum(r.right,t);}
    static int depth(TreeNode r){return r==null?0:1+Math.max(depth(r.left),depth(r.right));}
    public static void main(String[] a){
        TreeNode r=new TreeNode(-10);r.left=new TreeNode(9);r.right=new TreeNode(20);r.right.left=new TreeNode(15);r.right.right=new TreeNode(7);
        System.out.println("maxPath="+maxPathSum(r));
        System.out.println("depth="+depth(r));
        TreeNode r2=new TreeNode(3);r2.left=new TreeNode(5);r2.right=new TreeNode(1);
        System.out.println("lca="+lca(r2,r2.left,r2.right).val);
        boolean ok=maxPathSum(r)==42&&depth(r)==3&&lca(r2,r2.left,r2.right).val==3;
        System.out.println("All pass: "+ok);
    }
}
